slides.body:
prompt = "Is Baymax an AI?"

// Step 1: Tokenize — break text into pieces
tokens = ["Is", "Bay", "max", "an", "AI", "?"]

// Step 2: Embed — convert tokens to numbers
vectors = embed(tokens)

// Step 3: Attention — figure out what matters
// "Baymax" and "AI" are strongly connected

// Step 4: Generate — predict the next token
response = "Yes, Baymax is a fictional AI..."

// Nathan's approach (fictional but instructive)

training_data = BlueBook_search_engine.all_queries()
// Billions of real human conversations

model = train(
  data = training_data,
  architecture = "wetware_neural_mesh",
  objective = "predict_human_behavior"
)

// The key insight: Ava wasn't trained to think.
// She was trained to predict what humans want to hear.
